  const EMPTY = -1;
  const maxClaims = Math.floor(size / 8);
  const center = size / 2;

  // Find all our cells and opponent cells
  const ourCells = [];
  const opponentCells = [];
  const opponentFrontiers = new Set();

  for (let r = 0; r < size; r++) {
    for (let c = 0; c < size; c++) {
      if (grid[r][c] === id) {
        ourCells.push([r, c]);
      } else if (grid[r][c] !== EMPTY && grid[r][c] !== null) {
        opponentCells.push([r, c]);
      }
    }
  }

  // Identify opponent frontier cells (where they're likely to expand)
  for (const [r, c] of opponentCells) {
    const adjacent = [[r-1,c], [r+1,c], [r,c-1], [r,c+1]];
    for (const [nr, nc] of adjacent) {
      if (nr >= 0 && nr < size && nc >= 0 && nc < size && grid[nr][nc] === EMPTY) {
        opponentFrontiers.add(`${nr},${nc}`);
      }
    }
  }

  const candidates = [];
  const visited = new Set();

  // Find our frontier
  for (const [r, c] of ourCells) {
    const adjacent = [[r-1,c], [r+1,c], [r,c-1], [r,c+1]];

    for (const [nr, nc] of adjacent) {
      if (nr < 0 || nr >= size || nc < 0 || nc >= size) continue;
      if (grid[nr][nc] !== EMPTY) continue;

      const key = `${nr},${nc}`;
      if (visited.has(key)) continue;
      visited.add(key);

      // Count adjacencies
      let adjacentToUs = 0;
      let adjacentEnemies = 0;
      let adjacentEmpty = 0;

      const neighbors = [[nr-1,nc], [nr+1,nc], [nr,nc-1], [nr,nc+1]];
      for (const [nnr, nnc] of neighbors) {
        if (nnr < 0 || nnr >= size || nnc < 0 || nnc >= size) continue;
        if (grid[nnr][nnc] === id) {
          adjacentToUs++;
        } else if (grid[nnr][nnc] === EMPTY) {
          adjacentEmpty++;
        } else if (grid[nnr][nnc] !== null) {
          adjacentEnemies++;
        }
      }

      let score = 0;

      // Early game: rush to center aggressively
      const gameProgress = ourCells.length / (size * size);
      const distFromCenter = Math.hypot(nr - center, nc - center);

      if (gameProgress < 0.05) {
        // Very early: prioritize center heavily
        score += (center - distFromCenter) * 1000;
      } else {
        score += (center - distFromCenter) * 100;
      }

      // High priority: block opponent expansion by claiming cells they want
      const isOpponentFrontier = opponentFrontiers.has(key);
      if (isOpponentFrontier) {
        score += 2000; // Very high priority to contest opponent moves
      }

      // Blocking enemy territory directly
      score += adjacentEnemies * 800;

      // Prefer cells with high adjacency to us (solidify territory)
      score += adjacentToUs * 400;

      // Expansion potential
      score += adjacentEmpty * 100;

      // Prevent being surrounded: penalize cells far from our center
      if (ourCells.length > 0) {
        const ourCenterRow = ourCells.reduce((sum, [rr]) => sum + rr, 0) / ourCells.length;
        const ourCenterCol = ourCells.reduce((sum, [, cc]) => sum + cc, 0) / ourCells.length;
        const distFromOurCenter = Math.hypot(nr - ourCenterRow, nc - ourCenterCol);

        // Penalty increases with distance to maintain compactness
        score -= distFromOurCenter * 50;
      }

      // Encirclement strategy: if we can reach around opponents, prioritize that
      if (opponentCells.length > 0 && opponentCells.length < ourCells.length) {
        const oppCenterRow = opponentCells.reduce((sum, [rr]) => sum + rr, 0) / opponentCells.length;
        const oppCenterCol = opponentCells.reduce((sum, [, cc]) => sum + cc, 0) / opponentCells.length;

        // Calculate if this cell is on opposite side of opponent from us
