        const ourCenterCol = ourCells.reduce((sum, [, cc]) => sum + cc, 0) / ourCells.length;

        const angleToOpp = Math.atan2(oppCenterRow - ourCenterRow, oppCenterCol - ourCenterCol);
        const angleToCell = Math.atan2(nr - ourCenterRow, nc - ourCenterCol);
        const angleDiff = Math.abs(angleToOpp - angleToCell);

        if (angleDiff > Math.PI / 2) {
          // Cell is on flanking angle - good for encirclement
          score += 300;
        }
      }

      candidates.push({ row: nr, col: nc, score });
    }
  }

  candidates.sort((a, b) => b.score - a.score);

  return candidates.slice(0, maxClaims * 2).map(c => [c.row, c.col]);
}
